patch:
--- a/multiplier.sv
+++ b/multiplier.sv
@@ -8,9 +8,9 @@ endmodule

 module tb_multiplier;
   reg [7:0] x, y;
-  wire [15:0] product;
+  wire [15:0] prod;

   multiplier_8bit mult_inst (
     .x(x),
     .y(y),
-    .product(product)
+    .prod(prod)
   );
 endmodule

before_code:
module multiplier_8bit (
  input [7:0] x,
  input [7:0] y,
  output [15:0] prod
);
  assign prod = x * y;
endmodule

module tb_multiplier;
  reg [7:0] x, y;
  wire [15:0] product;

  multiplier_8bit mult_inst (
    .x(x),
    .y(y),
    .product(product)
  );
endmodule

after_code:
module multiplier_8bit (
  input [7:0] x,
  input [7:0] y,
  output [15:0] prod
);
  assign prod = x * y;
endmodule

module tb_multiplier;
  reg [7:0] x, y;
  wire [15:0] prod;

  multiplier_8bit mult_inst (
    .x(x),
    .y(y),
    .prod(prod)
  );
endmodule
